sql:
SELECT name 
FROM billionaires 
WHERE marital_status = 'Married' AND children > 0;

SELECT AVG(net_worth) AS average_net_worth
FROM billionaires
WHERE self_made = 1;

SELECT name, net_worth
FROM billionaires
WHERE net_worth = (SELECT MAX(net_worth) FROM billionaires);

SELECT COUNT(*) AS 'Total billionaires with a degree in computer science'
FROM billionaire_education
WHERE degree LIKE '%Computer Science%';

SELECT COUNT(billionaire_id) AS num_married_billionaires
FROM billionaires
WHERE net_worth > 50.0 AND marital_status = 'Married';

SELECT country, AVG(net_worth) AS average_net_worth
FROM billionaires
GROUP BY country;

SELECT AVG(net_worth) AS average_net_worth_self_made_with_child
FROM billionaires
WHERE self_made = 1 AND children > 0;

external_knowledge:
- "sea level" metaphorically refers to the average net worth;
- "titans of wealth" metaphorically refers to billionaires;
- "positions in the global ranking of affluence" refers to the rank based on net worth.

